struct DDBEntry {
    uint8_t _hex[3];      // 24-bit ICAO
    uint32_t offset;      // offset into DDB_STRINGS
    const char *reg() const { return &DDB_STRINGS[offset]; }
    uint32_t hex() const {
        return (uint32_t(_hex[0]) << 16) |
               (uint32_t(_hex[1]) << 8)  |
               (uint32_t(_hex[2]));
    }
};

